package schema

import (
	"entgo.io/contrib/entgql"
	"entgo.io/ent"
	"entgo.io/ent/schema"
	"entgo.io/ent/schema/edge"
	"entgo.io/ent/schema/field"
)

// Secret has NO entgqlmulti.ApiConfig annotation.
// It must therefore be absent from every per-API schema generated by entgqlmulti
// (apidash, apipub, apimobile), even though User has an edge to it.
type Secret struct {
	ent.Schema
}

func (Secret) Fields() []ent.Field {
	return []ent.Field{
		field.String("token").Sensitive(),
	}
}

func (Secret) Edges() []ent.Edge {
	return []ent.Edge{
		edge.From("owner", User.Type).
			Ref("secrets").
			Unique(),
	}
}

func (Secret) Annotations() []schema.Annotation {
	// Secret is deliberately excluded from per-API schemas.
	// Keep entgql annotations off so it doesn't appear in the monolithic
	// Query either — the full schema will still include the type, but no
	// entgqlmulti target references it.
	return []schema.Annotation{
		entgql.Skip(entgql.SkipAll),
	}
}
